// src/App.js
import React, { useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import LandingPage from './pages/LandingPage';
import HomePage from './pages/HomePage';
import About from './pages/About';
import Contact from './pages/Contact';
import Dashboard from './pages/Dashboard';
import AdminPanel from './pages/AdminPanel'; // ✅ Import Admin Panel
import Profile from './pages/Profile';
import AllFriends from './pages/AllFriends';
import PasswordReset from './components/PasswordReset'; // Import Password Reset
import OAuthCallback from './components/OAuthCallback'; // OAuth callback handler
import RequireAuth from './components/RequireAuth';
import HostDashboard from './pages/HostDashboard';
import HostPage from './pages/HostPage';
import ReviewPage from './pages/ReviewPage';
import CertificateVerify from './pages/CertificateVerify';
import AdminVerification from './pages/AdminVerification';
import HostRegister from './components/HostRegister';
import PaymentUIDemo from './components/PaymentUIDemo';
import { ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import Settings from './pages/Settings';
import ChatPage from './pages/ChatPage';
import ChatOverlay from './components/chat/ChatOverlay';
import SupportChatbot from './components/SupportChatbot';
function ChatbotGate() {
  const location = useLocation();
  const path = location.pathname;
  let role = null;
  try {
    const u = JSON.parse(localStorage.getItem('user') || 'null');
    role = u?.role || null;
  } catch {}
  const show =
    (path === '/dashboard' && role === 'student') ||
    (path === '/host-dashboard' && role === 'host');
  return show ? <SupportChatbot /> : null;
}

export default function App() {
  // Apply persisted UI preferences (density) on startup
  useEffect(() => {
    try {
      const d = localStorage.getItem('ui_density');
      if (d) {
        document.documentElement.setAttribute('data-density', d);
      } else {
        document.documentElement.setAttribute('data-density', 'compact');
      }
    } catch {
      document.documentElement.setAttribute('data-density', 'compact');
    }
  }, []);
  return (
    <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
      <ToastContainer
        position="top-right"
        autoClose={4000}
        hideProgressBar={false}
        newestOnTop={true}
        closeOnClick={true}
        rtl={false}
        pauseOnFocusLoss={true}
        draggable={true}
        pauseOnHover={true}
        theme="dark"
        style={{ top: '20px', right: '20px', zIndex: 9999 }}
      />
      <Routes>
        {/* New landing page as the first page */}
        <Route path="/" element={<LandingPage />} />

        {/* Keep old HomePage accessible as a login screen */}
        <Route path="/login" element={<HomePage />} />
        <Route path="/about" element={<About />} />
        <Route path="/contact" element={<Contact />} />

        <Route
          path="/dashboard"
          element={
            <RequireAuth allowedRoles={['student', 'admin', 'host']}>
              <Dashboard />
            </RequireAuth>
          }
        />
        <Route
          path="/admin/verification"
          element={
            <RequireAuth allowedRoles={['admin']}>
              <AdminVerification />
            </RequireAuth>
          }
        />
        <Route
          path="/admin"
          element={
            <RequireAuth allowedRoles={['admin']}>
              <AdminPanel />
            </RequireAuth>
          }
        />
        <Route
          path="/host-dashboard"
          element={
            <RequireAuth allowedRoles={['host', 'admin']}>
              <HostDashboard />
            </RequireAuth>
          }
        />
        <Route path="/review/:eventId" element={<ReviewPage />} />
        <Route path="/host/:hostId" element={<HostPage />} />
        <Route path="/certificate/:id" element={<CertificateVerify />} />
        <Route path="/register-host" element={<HostRegister />} />
        <Route path="/reset-password" element={<PasswordReset />} />
        <Route path="/oauth-callback" element={<OAuthCallback />} />
        <Route path="/payment-demo" element={<PaymentUIDemo />} />
        <Route
          path="/profile"
          element={
            <RequireAuth allowedRoles={['student', 'host', 'admin']}>
              <Profile />
            </RequireAuth>
          }
        />
        <Route
          path="/settings"
          element={
            <RequireAuth allowedRoles={['student', 'host', 'admin']}>
              <Settings />
            </RequireAuth>
          }
        />
        <Route
          path="/profile/friends"
          element={
            <RequireAuth allowedRoles={['student', 'host', 'admin']}>
              <AllFriends />
            </RequireAuth>
          }
        />
        <Route
          path="/chat"
          element={
            <RequireAuth allowedRoles={['student', 'host', 'admin']}>
              <ChatPage />
            </RequireAuth>
          }
        />
      </Routes>
      <ChatbotGate />
      <ChatOverlay />
    </Router>
  );
}

import React, { useState } from 'react';
import { X, Award, CheckCircle, Lock, TrendingUp, Star } from 'lucide-react';

const BadgeDetailModal = ({ badge, isOpen, onClose, earned, progress = {} }) => {
  if (!isOpen || !badge) return null;

  const getRarityColor = (rarity) => {
    switch (rarity) {
      case 'common':
        return 'text-slate-600 bg-slate-100 border-slate-300';
      case 'uncommon':
        return 'text-green-600 bg-green-100 border-green-300';
      case 'rare':
        return 'text-blue-600 bg-blue-100 border-blue-300';
      case 'epic':
        return 'text-purple-600 bg-purple-100 border-purple-300';
      case 'legendary':
        return 'text-amber-600 bg-amber-100 border-amber-300';
      default:
        return 'text-slate-600 bg-slate-100 border-slate-300';
    }
  };

  const getRarityLabel = (rarity) => {
    return rarity ? rarity.charAt(0).toUpperCase() + rarity.slice(1) : 'Common';
  };

  // Calculate overall progress
  const totalRequired = badge.criteria?.reduce((sum, c) => sum + c.required, 0) || 1;
  const totalCurrent =
    badge.criteria?.reduce((sum, c) => {
      const current = progress[c.id] || c.current || 0;
      return sum + Math.min(current, c.required);
    }, 0) || 0;
  const overallProgress = Math.round((totalCurrent / totalRequired) * 100);

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm"
      onClick={onClose}
    >
      <div
        className="bg-white rounded-2xl shadow-2xl max-w-md w-full overflow-hidden transform transition-all"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div
          className={`relative p-6 ${earned ? 'bg-gradient-to-br from-blue-500 to-blue-600' : 'bg-gradient-to-br from-slate-200 to-slate-300'}`}
        >
          <button
            onClick={onClose}
            className="absolute top-4 right-4 p-1.5 rounded-lg bg-white/20 hover:bg-white/30 text-white transition-colors"
          >
            <X className="w-5 h-5" />
          </button>

          {/* Badge Icon */}
          <div className="flex flex-col items-center">
            <div
              className={`relative w-24 h-24 rounded-full flex items-center justify-center text-5xl mb-4 ${
                earned ? 'bg-white shadow-lg ring-4 ring-white/50' : 'bg-slate-100 opacity-60'
              }`}
            >
              {badge.icon}
              {!earned && (
                <div className="absolute inset-0 flex items-center justify-center bg-slate-900/40 rounded-full backdrop-blur-sm">
                  <Lock className="w-8 h-8 text-white" />
                </div>
              )}
            </div>

            <h2 className="text-2xl font-bold text-white mb-1">{badge.name}</h2>
            <p className="text-white/90 text-sm mb-3">{badge.description}</p>

            {/* Rarity Badge */}
            <div
              className={`px-3 py-1 rounded-full text-xs font-bold border ${getRarityColor(badge.rarity)}`}
            >
              {getRarityLabel(badge.rarity)}
            </div>
          </div>
        </div>

        {/* Content */}
        <div className="p-6">
          {/* Points Reward */}
          <div className="flex items-center justify-between mb-6 p-4 bg-amber-50 border border-amber-200 rounded-xl">
            <div className="flex items-center gap-2">
              <Star className="w-5 h-5 text-amber-500" />
              <span className="font-semibold text-slate-900">Reward</span>
            </div>
            <span className="text-xl font-bold text-amber-600">+{badge.points} XP</span>
          </div>

          {/* Progress */}
          {!earned && (
            <div className="mb-6">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm font-semibold text-slate-700">Overall Progress</span>
                <span className="text-sm font-bold text-blue-600">{overallProgress}%</span>
              </div>
              <div className="h-2.5 bg-slate-100 rounded-full overflow-hidden">
                <div
                  className="h-full bg-gradient-to-r from-blue-500 to-blue-600 rounded-full transition-all duration-500"
                  style={{ width: `${overallProgress}%` }}
                />
              </div>
            </div>
          )}

          {/* Criteria */}
          <div>
            <h3 className="text-sm font-bold text-slate-900 mb-3 flex items-center gap-2">
              <TrendingUp className="w-4 h-4 text-blue-600" />
              {earned ? 'Completion Criteria' : 'Requirements'}
            </h3>
            <div className="space-y-3">
              {badge.criteria?.map((criterion) => {
                const current = progress[criterion.id] || criterion.current || 0;
                const isComplete = current >= criterion.required;
                const criterionProgress = Math.min(100, (current / criterion.required) * 100);

                return (
                  <div key={criterion.id} className="space-y-2">
                    <div className="flex items-start gap-3">
                      <div
                        className={`mt-0.5 flex-shrink-0 w-5 h-5 rounded-full flex items-center justify-center ${
                          isComplete ? 'bg-green-500 text-white' : 'bg-slate-200 text-slate-400'
                        }`}
                      >
                        {isComplete ? (
                          <CheckCircle className="w-3.5 h-3.5" />
                        ) : (
                          <div className="w-2 h-2 rounded-full bg-slate-400" />
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p
                          className={`text-sm font-medium ${isComplete ? 'text-slate-900' : 'text-slate-600'}`}
                        >
                          {criterion.label}
                        </p>
                        <div className="flex items-center gap-2 mt-1">
                          <div className="flex-1 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                            <div
                              className={`h-full rounded-full transition-all duration-300 ${
                                isComplete ? 'bg-green-500' : 'bg-blue-500'
                              }`}
                              style={{ width: `${criterionProgress}%` }}
                            />
                          </div>
                          <span className="text-xs font-semibold text-slate-500 whitespace-nowrap">
                            {current}/{criterion.required}
                          </span>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Earned Status */}
          {earned && (
            <div className="mt-6 p-4 bg-green-50 border border-green-200 rounded-xl flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-green-500 flex items-center justify-center">
                <CheckCircle className="w-6 h-6 text-white" />
              </div>
              <div>
                <p className="font-bold text-green-900">Badge Unlocked!</p>
                <p className="text-xs text-green-700">You've earned this achievement</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default BadgeDetailModal;

import React, { useEffect, useState } from 'react';
import config from '../config';
import {
  X,
  Calendar,
  MapPin,
  Clock,
  Users,
  Tag,
  Globe,
  Phone,
  Mail,
  CreditCard,
  Bookmark,
  BookmarkCheck,
  Building2,
  MessageSquare,
  Trophy,
  CheckCircle,
  ExternalLink,
  Lock,
  Share2,
  Navigation,
  FileText,
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import FriendSelectorModal from './FriendSelectorModal';
import { getImageUrl } from '../utils/imageUtils';

const EventDetailModal = ({
  event,
  isOpen,
  onClose,
  user,
  onRegister,
  onBookmark,
  onSubscribe,
  onNavigateToReview,
  onDownloadCertificate,
  isRegistered,
  isBookmarked,
  isSubscribed,
  onOpenHost,
  certificateId,
  disabledActions = false,
}) => {
  const [loading, setLoading] = useState(false);
  const [copySuccess, setCopySuccess] = useState(false);
  const [friendSelectorOpen, setFriendSelectorOpen] = useState(false);

  const handleChatShare = (friend) => {
    const dt = event.date ? new Date(event.date) : null;
    const dateStr = dt
      ? dt.toLocaleDateString('en-IN', { weekday: 'short', month: 'short', day: 'numeric' })
      : 'Date TBA';
    const timeStr = dt
      ? dt.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })
      : '';
    const loc = event.isOnline ? event.platform || 'Online' : event.location || 'Location TBA';
    const price = event.price > 0 ? `₹${event.price}` : 'Free';

    const msg = `📅 *${event.title}*
🗓 ${dateStr} • ${timeStr}
📍 ${loc}
💰 ${price}

Check it out here: ${window.location.href}`;

    window.dispatchEvent(
      new CustomEvent('open-chat', {
        detail: {
          friendId: friend._id,
          friendName: friend.fullname || friend.username,
          friendPic: friend.profilePic,
          initialMessage: msg,
        },
      })
    );
    setFriendSelectorOpen(false);
  };

  if (!isOpen || !event) return null;

  // Normalize helpers
  const registered = typeof isRegistered === 'function' ? isRegistered(event._id) : !!isRegistered;
  const bookmarked = typeof isBookmarked === 'function' ? isBookmarked(event._id) : !!isBookmarked;

  const handleRegister = async () => {
    setLoading(true);
    try {
      await onRegister(event);
    } finally {
      setLoading(false);
    }
  };

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href);
    setCopySuccess(true);
    setTimeout(() => setCopySuccess(false), 2000);
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-IN', {
      weekday: 'short',
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    });
  };

  const formatTime = (dateString) => {
    return new Date(dateString).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
  };

  const formatCurrency = (amount, currency = 'INR') => {
    return new Intl.NumberFormat('en-IN', { style: 'currency', currency }).format(amount);
  };

  const deadline = event?.registrationDeadline ? new Date(event.registrationDeadline) : null;
  const now = new Date();
  const deadlinePassed = deadline && !isNaN(deadline.getTime()) && now > deadline;

  // Animation Variants
  const overlayVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1 },
  };

  const modalVariants = {
    hidden: { opacity: 0, scale: 0.95, y: 20 },
    visible: { opacity: 1, scale: 1, y: 0, transition: { type: 'spring', duration: 0.5 } },
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div
          key="main-event-modal"
          className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6"
          onClick={onClose}
        >
          {/* Backdrop */}
          <motion.div
            key="modal-backdrop"
            initial="hidden"
            animate="visible"
            exit="hidden"
            variants={overlayVariants}
            className="absolute inset-0 bg-black/60 backdrop-blur-sm"
          />

          {/* Modal Container */}
          <motion.div
            key="modal-container"
            initial="hidden"
            animate="visible"
            exit="hidden"
            variants={modalVariants}
            onClick={(e) => e.stopPropagation()}
            className="relative bg-white w-full max-w-4xl max-h-[90vh] shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] border-2 border-black overflow-hidden flex flex-col"
          >
            {/* --- HERO SECTION (Brutalist) --- */}
            <div className="relative h-48 sm:h-56 shrink-0 border-b-2 border-black">
              {/* Background Image */}
              <div className="absolute inset-0 bg-neutral-900">
                {event.imageUrl ? (
                  <img
                    src={getImageUrl(event.imageUrl)}
                    alt={event.title}
                    className="w-full h-full object-cover grayscale opacity-80"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-neutral-100 pattern-grid-lg">
                    <Calendar className="w-16 h-16 text-black" />
                  </div>
                )}
                {/* Overlay */}
                <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-90" />
              </div>

              {/* Close Button */}
              <button
                onClick={onClose}
                className="absolute top-4 right-4 p-2 bg-white text-black border-2 border-black hover:bg-black hover:text-white transition-colors z-10"
              >
                <X className="w-6 h-6" />
              </button>

              {/* Title Content */}
              <div className="absolute bottom-0 left-0 right-0 p-6 md:p-8">
                <div className="flex flex-wrap gap-2 mb-3">
                  <span
                    className={`px-3 py-1 text-[10px] font-bold uppercase tracking-widest border border-white text-white ${event.isOnline ? 'bg-blue-600' : 'bg-emerald-600'}`}
                  >
                    {event.isOnline ? event.platform || 'Online' : 'In-Person'}
                  </span>
                  {event.category && (
                    <span className="px-3 py-1 text-[10px] font-bold uppercase tracking-widest bg-white text-black border border-white">
                      {event.category}
                    </span>
                  )}
                  {event.isCompleted && (
                    <span className="px-3 py-1 text-[10px] font-bold uppercase tracking-widest bg-neutral-700 text-white border border-neutral-500">
                      Completed
                    </span>
                  )}
                </div>

                <h1 className="text-3xl md:text-5xl font-black text-white mb-2 uppercase tracking-tighter leading-none shadow-black drop-shadow-md">
                  {event.title}
                </h1>

                <div className="flex items-center gap-6 text-white text-xs md:text-sm font-bold uppercase tracking-wider">
                  <div
                    className="flex items-center gap-2 group cursor-pointer"
                    onClick={() => onOpenHost && onOpenHost(event.hostId?._id || event.hostId)}
                  >
                    {event.hostId?.profilePic ? (
                      <img
                        src={getImageUrl(event.hostId.profilePic)}
                        className="w-6 h-6 rounded-none border border-white object-cover grayscale group-hover:grayscale-0 transition-all"
                        alt="Host"
                      />
                    ) : (
                      <div className="w-6 h-6 bg-white border border-white flex items-center justify-center">
                        <Building2 className="w-4 h-4 text-black" />
                      </div>
                    )}
                    <span className="hover:underline decoration-2 underline-offset-4">
                      {event.hostId?.fullname || event.hostId?.username || 'Host'}
                    </span>
                  </div>
                  {event.date && (
                    <div className="flex items-center gap-2">
                      <Calendar className="w-4 h-4" />
                      <span>{formatDate(event.date)}</span>
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* --- CONTENT LAYOUT --- */}
            <div className="flex-1 overflow-y-auto bg-white">
              <div className="grid grid-cols-1 lg:grid-cols-3">
                {/* LEFT COLUMN: Main Info */}
                <div className="lg:col-span-2 p-6 md:p-8 space-y-8 border-b-2 lg:border-b-0 lg:border-r-2 border-black">
                  {/* Quick Stats Grid */}
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-0 border-2 border-black divide-x-2 divide-black bg-white">
                    <div className="p-4 flex flex-col items-center text-center hover:bg-neutral-50 transition-colors">
                      <Clock className="w-5 h-5 text-black mb-2" />
                      <div className="text-[10px] uppercase font-bold text-neutral-500 tracking-widest">
                        Time
                      </div>
                      <div className="text-xs font-bold text-black uppercase">
                        {formatTime(event.date)}
                      </div>
                    </div>
                    <div className="p-4 flex flex-col items-center text-center hover:bg-neutral-50 transition-colors">
                      <MapPin className="w-5 h-5 text-black mb-2" />
                      <div className="text-[10px] uppercase font-bold text-neutral-500 tracking-widest">
                        Location
                      </div>
                      <div
                        className="text-xs font-bold text-black uppercase truncate w-full"
                        title={event.location}
                      >
                        {event.isOnline ? event.platform || 'Online' : event.location || 'TBA'}
                      </div>
                    </div>
                    <div className="p-4 flex flex-col items-center text-center hover:bg-neutral-50 transition-colors">
                      <Users className="w-5 h-5 text-black mb-2" />
                      <div className="text-[10px] uppercase font-bold text-neutral-500 tracking-widest">
                        Capacity
                      </div>
                      <div className="text-xs font-bold text-black uppercase">
                        {event.capacity ? event.capacity : 'Unlimited'}
                      </div>
                    </div>
                    <div className="p-4 flex flex-col items-center text-center hover:bg-neutral-50 transition-colors">
                      <Tag className="w-5 h-5 text-black mb-2" />
                      <div className="text-[10px] uppercase font-bold text-neutral-500 tracking-widest">
                        Price
                      </div>
                      <div className="text-xs font-bold text-black uppercase">
                        {event.price > 0 ? formatCurrency(event.price) : 'Free'}
                      </div>
                    </div>
                  </div>

                  {/* Description */}
                  <div className="space-y-4">
                    <h3 className="text-xl font-black text-black uppercase tracking-tight flex items-center gap-2 border-l-4 border-black pl-3">
                      About Event
                    </h3>
                    <div className="prose prose-sm max-w-none text-neutral-800 leading-relaxed font-medium">
                      {event.description || event.shortDescription || 'No description provided.'}
                    </div>
                  </div>

                  {/* Agenda/Requirements Row */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {event.agenda && (
                      <div className="border-2 border-black p-5 shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] bg-white">
                        <h3 className="text-sm font-black text-black mb-3 uppercase tracking-widest border-b-2 border-black pb-2">
                          Agenda
                        </h3>
                        <p className="text-neutral-700 text-sm whitespace-pre-line leading-relaxed font-mono">
                          {event.agenda}
                        </p>
                      </div>
                    )}
                    {event.requirements && (
                      <div className="border-2 border-black p-5 shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] bg-white">
                        <h3 className="text-sm font-black text-black mb-3 uppercase tracking-widest border-b-2 border-black pb-2">
                          Requirements
                        </h3>
                        <ul className="list-square pl-5 text-neutral-700 text-sm space-y-1 font-medium marker:text-black">
                          {event.requirements.split('\n').map((req, i) => (
                            <li key={i}>{req}</li>
                          ))}
                        </ul>
                      </div>
                    )}
                  </div>

                  {/* Tags */}
                  {event.tags && event.tags.length > 0 && (
                    <div className="pt-4 border-t-2 border-dashed border-neutral-300">
                      <div className="flex flex-wrap gap-2">
                        {event.tags.map((t) => (
                          <span
                            key={t}
                            className="px-3 py-1 bg-black text-white text-[10px] font-bold uppercase tracking-wider border border-black"
                          >
                            #{t}
                          </span>
                        ))}
                      </div>
                    </div>
                  )}
                </div>

                {/* RIGHT COLUMN: Action Sticky Sidebar */}
                <div className="lg:col-span-1 bg-neutral-50 p-6 md:p-8">
                  <div className="sticky top-6 space-y-6">
                    {/* Registration Card */}
                    <div className="bg-white border-2 border-black p-6 shadow-[6px_6px_0px_0px_rgba(0,0,0,1)] relative">
                      <div className="text-center mb-6 border-b-2 border-black pb-4 border-dashed">
                        <div className="text-[10px] text-neutral-500 uppercase font-bold tracking-widest mb-1">
                          Total Price
                        </div>
                        <div className="text-4xl font-black text-black tracking-tighter">
