      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div>
          <label className="block text-xs font-bold uppercase tracking-widest mb-2 text-neutral-500">
            City *
          </label>
          <input
            name="city"
            type="text"
