                    title="Decline"
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Outgoing Requests */}
      <div className="bg-yellow-50 border-2 border-black p-6 shadow-[6px_6px_0px_0px_rgba(0,0,0,1)]">
        <h4 className="font-black text-black uppercase tracking-widest text-sm mb-4 flex items-center gap-2 border-b-2 border-black pb-3">
          <Clock className="w-4 h-4" />
