        nextValue = parseFloat(num.toFixed(2));
      }
    } else if (field === 'capacity') {
      const num = parseInt(String(value).replace(/[^\d-]/g, ''), 10);
      nextValue = isNaN(num) || num < 0 ? 0 : num;
