    const newBadges = [];
    const earnedBadgeIds = new Set(userStats.badges.map((b) => (typeof b === 'string' ? b : b.id)));

    // Helper to get stat value
    const getStat = (id) => {
      switch (id) {
        case 'subscribe_hosts':
          return userStats.totalSubscriptions || 0;
        case 'friendsConnected':
          return userStats.totalFriends || 0;
        case 'bookmark_events':
          return userStats.totalBookmarks || 0;
