      if (e.key === 'Escape') setLightbox((prev) => ({ ...prev, open: false }));
      if (e.key === 'ArrowRight')
        setLightbox((prev) => ({ ...prev, index: (prev.index + 1) % (prev.images.length || 1) }));
      if (e.key === 'ArrowLeft')
        setLightbox((prev) => ({
          ...prev,
          index: (prev.index - 1 + (prev.images.length || 1)) % (prev.images.length || 1),
