      const ensureAt = (v) => {
        const s = String(v || '').trim();
        if (!s) return '';
        return s.startsWith('@') ? s : `@${s}`;
      };
      norm.twitter =
        norm.twitter && !/^https?:\/\//i.test(norm.twitter)
          ? ensureAt(norm.twitter)
          : norm.twitter || '';
      norm.instagram =
        norm.instagram && !/^https?:\/\//i.test(norm.instagram)
          ? ensureAt(norm.instagram)
          : norm.instagram || '';
