      setReadSet((prev) => {
        const next = new Set(prev);
        next.add(n._key);
        localStorage.setItem(HOST_NOTIF_READ_KEY, JSON.stringify(Array.from(next)));
        return next;
      });
      setNotifications((prev) =>
        prev.map((notif) => (notif._key === n._key ? { ...notif, read: true } : notif))
