        const u = userRaw ? JSON.parse(userRaw) : null;
        if (!u?._id) return;
        const { data } = await api.get(`/api/host/public/host/${u._id}`, { headers: bearer() });
        const h = data?.host || {};
        setHostProfile({
          bio: h.bio || '',
          website: h.website || '',
          socials: h.socials || { twitter: '', instagram: '', linkedin: '' },
