              .map((tag) => tag.trim())
              .filter((tag) => tag)
          : [],
        capacity: parseInt(form.capacity) || 0,
        price: parseFloat(form.price) || 0,
        isOnline: Boolean(form.isOnline),
        coordinates:
          form.latitude && form.longitude
            ? [parseFloat(form.longitude), parseFloat(form.latitude)]
