            </section>
          </div>
        )}

        {activeTab === 'events' &&
          (hostEvents.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-2xl border border-slate-200 border-dashed">
              <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-slate-50 flex items-center justify-center">
                <Users className="w-8 h-8 text-slate-300" />
              </div>
              <h3 className="text-lg font-semibold text-slate-900 mb-1">No Events Found</h3>
              <p className="text-slate-500 text-sm">
                Try adjusting your search or come back later.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {hostEvents.map((ev) => (
                <GamifiedEventCard
                  key={ev._id}
                  event={ev}
                  onRegister={() => registerForEvent(ev)}
                  onBookmark={() => toggleBookmark(ev)}
                  onViewMore={() => openDetails(ev)}
                  isRegistered={registrations.some((r) => r.eventId === ev._id)}
                  isBookmarked={bookmarks.includes(ev._id)}
                />
              ))}
            </div>
          ))}

        {activeTab === 'about' && (
          <div className="bg-white border border-slate-200 rounded-2xl p-8 shadow-sm max-w-4xl mx-auto">
            <h3 className="text-xl font-bold text-slate-900 mb-6 border-b border-slate-100 pb-4">
              About the Host
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-y-6 gap-x-12 text-sm">
              <div className="space-y-1">
                <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
                  Host Name
                </span>
                <div className="text-base font-medium text-slate-900">
                  {host?.fullname || host?.username}
                </div>
              </div>
              <div className="space-y-1">
                <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
                  Institute/Organization
                </span>
                <div className="text-base font-medium text-slate-900 flex items-center gap-2">
                  <Building2 className="w-4 h-4 text-slate-400" />{' '}
                  {host?.institute || 'Not specified'}
                </div>
              </div>
              <div className="space-y-1">
                <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
                  Location
                </span>
                <div className="text-base font-medium text-slate-900">
                  {host?.city || 'Not specified'}
                </div>
              </div>
              <div className="space-y-1">
                <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
                  Website
                </span>
                <div>
                  {host?.website ? (
                    <a
                      className="text-blue-600 hover:underline font-medium"
                      href={host.website}
                      target="_blank"
                      rel="noreferrer"
                    >
                      {host.website}
                    </a>
                  ) : (
                    <span className="text-slate-400">Not available</span>
                  )}
                </div>
              </div>
            </div>
            {host?.bio && (
              <div className="mt-8 pt-6 border-t border-slate-100">
                <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider block mb-3">
                  Bio
                </span>
                <div className="text-slate-600 leading-relaxed whitespace-pre-line text-base">
                  {host.bio}
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {detailOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          <EventDetailModal
            event={selectedEvent}
            isOpen={detailOpen}
            onClose={() => {
              closeDetails();
            }}
            user={user}
            onRegister={registerForEvent}
            onBookmark={toggleBookmark}
            {...(!isOwnHost ? { onSubscribe: () => toggleSubscribe() } : {})}
            onNavigateToReview={(eventId) => {
              closeDetails();
              navigate(`/review/${eventId}`);
            }}
            onDownloadCertificate={() => toast.info('Coming soon')}
            isRegistered={registrations.some((r) => r.eventId === selectedEvent?._id)}
            isBookmarked={bookmarks.includes(selectedEvent?._id)}
            isSubscribed={isOwnHost ? false : isSubscribed}
          />
        </div>
      )}
      {scannerOpen && (
        <QRCodeScanner onScanSuccess={handleScanSuccess} onClose={() => setScannerOpen(false)} />
      )}
    </div>
  );
}

﻿﻿// src/pages/Profile.jsx
import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../utils/api';
import { uploadProfilePicture, uploadBanner } from '../utils/cloudinary';
import { getProfilePictureUrl, getBannerUrl } from '../utils/imageUtils';
import {
  Mail,
  Phone,
  ShieldCheck,
  Send,
  CheckCircle2,
  Save,
  UserCircle2,
  Edit3,
  AlertCircle,
  CheckCircle,
  Loader2,
  Trophy,
  MapPin,
  ArrowLeft,
  ImagePlus,
  Upload,
} from 'lucide-react';
import { useUser, useUpdateUser } from '../hooks/useUser';

// Local UI helpers — brutalist style
const Stat = ({ label, value }) => (
  <div className="p-4 bg-blue-50 border-2 border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,1)]">
    <div className="text-[10px] text-black font-black uppercase tracking-widest mb-1">{label}</div>
    <div className="text-3xl font-black text-black">{value}</div>
  </div>
);

const Chip = ({ text }) => (
  <span className="px-3 py-1.5 bg-blue-50 border-2 border-black text-black text-xs font-black uppercase tracking-wide shadow-[2px_2px_0px_0px_rgba(0,0,0,1)]">
    {text}
  </span>
);

// Brutalist input
const Field = ({ label, error, touched, children }) => (
  <div>
    <label className="block text-[10px] font-black uppercase tracking-widest text-black mb-1.5">
      {label}
    </label>
    {children}
    {error && touched && (
      <div className="mt-1 text-[10px] text-red-700 font-bold flex items-center gap-1 uppercase tracking-wide">
        <AlertCircle className="w-3 h-3" /> {error}
      </div>
    )}
  </div>
);

const inputBase =
  'w-full px-3 py-2.5 bg-white border-2 border-black outline-none text-black font-medium text-sm focus:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] transition-shadow';
const inputDisabled = 'opacity-50 cursor-not-allowed bg-neutral-100';

export default function Profile() {
  const { data: userData, isLoading: isUserLoading, refetch: refetchUser } = useUser();
  const updateUserMutation = useUpdateUser();

  const [saving, setSaving] = useState(false);
  const [me, setMe] = useState(null);
  const [form, setForm] = useState({});
  const [original, setOriginal] = useState(null);
  const [emailCode, setEmailCode] = useState('');
  const [phoneCode, setPhoneCode] = useState('');
  const [touched, setTouched] = useState({});
  const [focused, setFocused] = useState({});
  const [errors, setErrors] = useState({});
  const [selectedFile, setSelectedFile] = useState(null);
  const [selectedBanner, setSelectedBanner] = useState(null);
  const [friends, setFriends] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [subTab, setSubTab] = useState('About');
  const [stats, setStats] = useState(null);
  const [attendance, setAttendance] = useState([]);
  const [certs, setCerts] = useState([]);
  const uniqueKey = (c) =>
    c?.eventId ||
    String(c?.title || '')
      .trim()
      .toLowerCase() ||
    c?.id;

  const uniqueCerts = useMemo(() => {
    const seen = new Set();
    return (Array.isArray(certs) ? certs : []).filter((c) => {
      const key = uniqueKey(c);
      if (!key) return true;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }, [certs]);

  const [imgBust, setImgBust] = useState(0);
  const [editing, setEditing] = useState(false);
  const [badgeEdit, setBadgeEdit] = useState(false);
  const [selectedBadges, setSelectedBadges] = useState([]);
  const navigate = useNavigate();
  const location = useLocation();

  const params = new URLSearchParams(location.search || '');
  const mode = (params.get('mode') || '').toLowerCase();
  const tabParam = (params.get('tab') || '').toLowerCase();
  const isCredentials =
    mode === 'credentials' || ['credentials', 'otp', 'verify', 'verification'].includes(tabParam);
  const isPhoto = mode === 'photo' || tabParam === 'photo';
  const isView = mode === 'view' || params.get('view') === '1';
  const isUpdate = !isCredentials && !isPhoto;

  const isValidPhone = /^\d{10}$/.test(String(form.phone || ''));
  const isValidPhoneOTP = /^\d{6}$/.test(String(phoneCode || ''));

  useEffect(() => {
    if (userData) {
      const d = userData;
      setMe(d);
      setForm((prev) => ({
        ...prev,
        username: d.username || '',
        fullname: d.fullname || '',
        institute: d.institute || '',
        street: d.street || '',
        city: d.city || '',
        pincode: d.pincode || '',
        age: d.age || '',
        course: d.course || '',
        email: d.email || '',
        phone: d.phone || '',
        countryCode: d.countryCode || '+91',
        bio: d.bio || '',
        bannerUrl: d.bannerUrl || '',
        profilePic: d.profilePic || '',
      }));
      setOriginal({
        username: d.username || '',
        fullname: d.fullname || '',
        institute: d.institute || '',
        street: d.street || '',
        city: d.city || '',
        pincode: d.pincode || '',
        age: d.age || '',
        course: d.course || '',
        email: d.email || '',
        phone: d.phone || '',
        countryCode: d.countryCode || '+91',
        bio: d.bio || '',
        bannerUrl: d.bannerUrl || '',
        profilePic: d.profilePic || '',
      });
    }
  }, [userData]);

  useEffect(() => {
    const initial =
      Array.isArray(me?.displayBadges) && me.displayBadges.length
        ? me.displayBadges
        : Array.isArray(stats?.badges)
          ? stats.badges.slice(0, 3)
          : [];
    setSelectedBadges(initial);
  }, [me, stats]);

  useEffect(() => {
    const uid = me?.id || me?._id;
    if (!uid) return;
    let cancelled = false;
    (async () => {
      try {
        const token = localStorage.getItem('token');
        const auth = token ? { headers: { Authorization: `Bearer ${token}` } } : {};
        const [st, att, cert] = await Promise.all([
          api.get(`/api/users/${uid}/stats`, auth),
          api.get(`/api/users/${uid}/attendance`, auth),
          api.get(`/api/users/${uid}/certificates`, auth),
        ]);
        if (cancelled) return;
        setStats(st.data || null);
        setAttendance(Array.isArray(att.data) ? att.data : []);
        setCerts(Array.isArray(cert.data) ? cert.data : []);
      } catch (e) {
        if (cancelled) return;
        setStats({
          totalEvents: 0,
          completedEvents: 0,
          byCategory: {},
          streak: 0,
          interests: [],
          badges: [],
        });
        setAttendance([]);
        setCerts([]);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [me?.id, me?._id]);

  const toggleBadge = (badge) => {
    setSelectedBadges((prev) => {
      const exists = prev.includes(badge);
      let next = exists ? prev.filter((b) => b !== badge) : [...prev, badge];
      if (next.length > 3) next = next.slice(0, 3);
      return next;
    });
  };

  const sendBothOTPs = async () => {
    try {
      await sendEmailOTP();
    } catch (_) {}
    try {
      await sendPhoneOTP();
    } catch (_) {}
  };

  const saveBadges = async () => {
    try {
      setSaving(true);
      const token = localStorage.getItem('token');
      await api.put(
        '/api/auth/display-badges',
        { badges: selectedBadges },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      toast.success('Badges updated');
      setBadgeEdit(false);
      await refetchUser();
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Failed to update badges');
    } finally {
      setSaving(false);
    }
  };

  const validateField = (key, val) => {
    const value = String(val ?? '').trim();
    if (value === '' && !touched[key]) return '';
    switch (key) {
      case 'email':
        if (!value) return 'Email is required';
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value) ? '' : 'Please enter a valid email address';
      case 'phone':
        if (!value) return 'Phone number is required';
        return /^\d{10}$/.test(value) ? '' : 'Phone must be 10 digits';
      case 'pincode':
        if (!value) return 'Pincode is required';
        return /^\d{6}$/.test(value) ? '' : 'Pincode must be 6 digits';
      case 'countryCode':
        if (!value) return 'Country code is required';
        return /^\+\d{1,4}$/.test(value) ? '' : 'Enter a valid country code (e.g., +91)';
      case 'age': {
        if (!value) return 'Age is required';
        const n = parseInt(value, 10);
        if (isNaN(n)) return 'Please enter a valid number';
        if (n < 16) return 'You must be at least 16 years old';
        if (n > 100) return 'Please enter a valid age';
        return '';
      }
      case 'fullname':
        if (!value) return 'Full name is required';
        if (value.length < 2) return 'Name is too short';
        if (value.length > 100) return 'Name is too long';
        return /^[a-zA-Z\s-']+$/.test(value) ? '' : 'Name contains invalid characters';
      case 'username':
        if (!value) return 'Username is required';
        if (value.length < 3) return 'Username must be at least 3 characters';
        if (value.length > 30) return 'Username is too long';
        return /^[a-zA-Z0-9_.-]+$/.test(value) ? '' : 'Only letters, numbers, ., -, _ allowed';
      case 'institute':
        if (!value) return 'Institute is required';
        if (value.length > 200) return 'Institute name is too long';
        if (value.length < 2) return 'Institute name is too short';
        return '';
      case 'course':
        if (!value) return 'Department is required';
        if (value.length > 100) return 'Department name is too long';
        if (value.length < 1) return 'Department name is required';
        return '';
      case 'street':
        if (!value) return 'Street address is required';
        if (value.length > 100) return 'Street address is too long';
        if (value.length < 3) return 'Street address is too short';
        return '';
      case 'city':
        if (!value) return 'City is required';
        if (value.length > 100) return 'City name is too long';
        if (value.length < 2) return 'City name is too short';
        return '';
      default:
        return '';
    }
  };

  const handleBannerChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) {
      toast.error('File size must be < 5MB');
      return;
    }
    if (!file.type.startsWith('image/')) {
      toast.error('Please select an image file');
      return;
    }
    setSelectedBanner(file);
  };

  const uploadBannerImg = async () => {
    if (!selectedBanner) return;
    try {
      setUploading(true);
      const token = localStorage.getItem('token');
      const uploadResult = await uploadBanner(selectedBanner);
      if (!uploadResult.success) {
        toast.error(uploadResult.error || 'Failed to upload banner');
        return;
      }
      await updateUserMutation.mutateAsync({ bannerUrl: uploadResult.url });
      toast.success('Banner updated');
      setSelectedBanner(null);
      setImgBust(Date.now());
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Failed to upload banner');
    } finally {
      setUploading(false);
    }
  };

  const handleChange = (key, value) => {
    if (key === 'phone')
      value = String(value || '')
        .replace(/\D/g, '')
        .slice(0, 10);
    if (key === 'countryCode')
      value = String(value || '+').startsWith('+') ? String(value) : `+${value}`;
    setForm((prev) => ({ ...prev, [key]: value }));
    const hasFocusAndTouched = focused[key] && touched[key];
    if (hasFocusAndTouched) setErrors((prev) => ({ ...prev, [key]: validateField(key, value) }));
  };

  const handleFocus = (key) => {
    setFocused((prev) => ({ ...prev, [key]: true }));
    setTouched((prev) => ({ ...prev, [key]: true }));
    const error = validateField(key, form[key]);
    setErrors((prev) => ({ ...prev, [key]: error }));
    if (error) toast.warn(error, { autoClose: 3000 });
  };

  const handleBlur = (key) => {
    setFocused((prev) => ({ ...prev, [key]: false }));
    setTouched((prev) => ({ ...prev, [key]: true }));
    const error = validateField(key, form[key]);
    setErrors((prev) => ({ ...prev, [key]: error }));
    if (error) toast.error(error, { autoClose: 3000 });
  };

  const saveProfile = async () => {
    try {
      setSaving(true);
      const token = localStorage.getItem('token');
      const keysToCheck = [
        'institute',
        'course',
        'street',
        'city',
        'countryCode',
        'pincode',
        'age',
      ];
      const newErrors = {};
      keysToCheck.forEach((k) => {
        const msg = validateField(k, form[k]);
        if (msg) newErrors[k] = msg;
      });
      setErrors((prev) => ({ ...prev, ...newErrors }));
      const allTouched = {};
      keysToCheck.forEach((k) => {
        allTouched[k] = true;
      });
      setTouched((prev) => ({ ...prev, ...allTouched }));
      if (Object.values(newErrors).some(Boolean)) {
        toast.error('Please fix validation errors');
        return;
      }
      await updateUserMutation.mutateAsync(form);
      toast.success('Profile updated');
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Failed to update profile');
    } finally {
      setSaving(false);
    }
  };

  const sendEmailOTP = async () => {
    try {
      const token = localStorage.getItem('token');
      const { data } = await api.post(
        '/api/auth/send-email-otp',
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      );
      toast.success(data.message || 'Email OTP sent');
      if (data.devCode) toast.info(`Dev code: ${data.devCode}`);
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Failed to send email OTP');
    }
  };

  const verifyEmailOTP = async () => {
    try {
      const code = String(emailCode || '').trim();
      if (!/^\d{6}$/.test(code)) {
        toast.error('Enter the 6-digit email code');
        return;
      }
      const token = localStorage.getItem('token');
      const { data } = await api.post(
        '/api/auth/verify-email-otp',
        { code },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      toast.success(data.message || 'Email verified');
      await refetchUser();
      setEmailCode('');
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Invalid code');
    }
  };

  const sendPhoneOTP = async () => {
    try {
      if (!isValidPhone) {
        setTouched((prev) => ({ ...prev, phone: true }));
        setErrors((prev) => ({ ...prev, phone: validateField('phone', form.phone) }));
        return toast.error('Enter a valid 10-digit phone first');
      }
      const token = localStorage.getItem('token');
      const { data } = await api.post(
