                    ) : (
                      <>
                        <button
                          onClick={() => {
                            setForm(original || {});
                            setEditing(false);
                            setErrors({});
                          }}
                          className="px-6 py-3 bg-white border-2 border-black text-black font-black uppercase tracking-widest text-xs hover:bg-neutral-100 transition-all"
                        >
                          Cancel
                        </button>
                        <button
                          onClick={async () => {
                            await saveProfile();
                            setEditing(false);
                          }}
                          disabled={saving}
                          className="px-6 py-3 bg-black text-white border-2 border-black font-black uppercase tracking-widest text-xs shadow-[4px_4px_0px_0px_rgba(0,0,0,0.3)] hover:bg-neutral-800 disabled:opacity-50 transition-all"
                        >
                          {saving ? (
                            <>
                              <Loader2 className="w-4 h-4 inline animate-spin mr-2" />
                              Saving...
                            </>
                          ) : (
                            <>
                              <Save className="w-4 h-4 inline mr-2" />
                              Save Changes
                            </>
                          )}
                        </button>
                      </>
                    )}
                  </div>
                )}
              </div>
            )}

            {/* ── PROGRESS TAB ── */}
            {subTab === 'Progress' && (
              <div className="space-y-8">
                {!stats ? (
                  <div className="flex items-center gap-3 text-black font-black uppercase tracking-widest text-xs py-8">
                    <div className="w-4 h-4 border-2 border-black border-t-transparent animate-spin" />{' '}
                    Loading stats...
                  </div>
                ) : (
                  <>
                    {/* Stat cards */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                      <Stat label="Events" value={stats.totalEvents} />
                      <Stat label="Completed" value={stats.completedEvents} />
                      <Stat label="Streak" value={`${stats.streak}d`} />
                      <Stat label="Interests" value={(stats.interests || []).length} />
                    </div>

                    {/* By Category */}
                    <div className="bg-violet-50 border-2 border-black p-5 shadow-[4px_4px_0px_0px_rgba(0,0,0,1)]">
                      <div className="text-xs font-black uppercase tracking-widest text-black mb-4 border-b-2 border-black pb-2">
                        By Category
                      </div>
                      <div className="space-y-3">
                        {Object.entries(stats.byCategory || {}).map(([cat, n]) => (
                          <div key={cat} className="flex items-center gap-3">
                            <div className="w-28 text-[10px] text-black font-bold uppercase tracking-wide truncate">
                              {cat}
                            </div>
                            <div className="flex-1 h-4 bg-white border-2 border-black overflow-hidden">
                              <div
                                className="h-full bg-black"
                                style={{
                                  width: `${Math.min(100, (n / (stats.totalEvents || 1)) * 100)}%`,
                                }}
                              />
                            </div>
                            <div className="w-6 text-xs text-black font-black text-right">{n}</div>
                          </div>
                        ))}
                        {Object.keys(stats.byCategory || {}).length === 0 && (
                          <div className="text-xs text-slate-500 font-bold uppercase">
                            No category data yet.
                          </div>
                        )}
                      </div>
                    </div>

                    {/* Badges */}
                    <div className="bg-amber-50 border-2 border-black p-5 shadow-[4px_4px_0px_0px_rgba(0,0,0,1)]">
                      <div className="text-xs font-black uppercase tracking-widest text-black flex items-center justify-between border-b-2 border-black pb-2 mb-4">
                        <span>Badges</span>
                        {!badgeEdit ? (
                          <button
                            onClick={() => setBadgeEdit(true)}
                            className="px-3 py-1 bg-white border-2 border-black text-[10px] font-black uppercase shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] hover:bg-neutral-50 transition-all"
                          >
                            Edit Display
                          </button>
                        ) : (
                          <span className="text-[10px] text-slate-500 font-black uppercase">
                            Select up to 3
                          </span>
                        )}
                      </div>
                      {!badgeEdit ? (
                        <div className="flex flex-wrap gap-2">
                          {(selectedBadges.length ? selectedBadges : stats.badges || []).map(
                            (b, idx) => (
                              <Chip key={idx} text={b} />
                            )
                          )}
                          {!selectedBadges.length &&
                            (!stats.badges || stats.badges.length === 0) && (
                              <div className="text-xs text-slate-500 font-bold uppercase">
                                No badges yet.
                              </div>
                            )}
                        </div>
                      ) : (
                        <div className="space-y-4">
                          <div className="flex flex-wrap gap-2">
                            {(stats.badges || []).map((b) => {
                              const active = selectedBadges.includes(b);
                              return (
                                <button
                                  type="button"
                                  key={b}
                                  onClick={() => toggleBadge(b)}
                                  className={`px-3 py-1.5 border-2 border-black text-xs font-black uppercase tracking-wide transition-all shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] hover:translate-x-[-1px] hover:translate-y-[-1px] ${active ? 'bg-black text-white' : 'bg-white text-black hover:bg-neutral-50'}`}
                                >
                                  {b}
                                </button>
                              );
                            })}
                          </div>
                          <div className="text-[10px] text-slate-500 font-bold uppercase">
                            {selectedBadges.length}/3 selected
                          </div>
                          <div className="flex gap-2">
                            <button
                              onClick={saveBadges}
                              disabled={selectedBadges.length === 0 || saving}
                              className="px-4 py-2 bg-black text-white border-2 border-black text-xs font-black uppercase tracking-widest hover:bg-neutral-800 disabled:opacity-50 shadow-[3px_3px_0px_0px_rgba(0,0,0,0.3)] transition-all"
                            >
                              {saving ? 'Saving...' : 'Save Badges'}
                            </button>
                            <button
                              onClick={() => {
                                setSelectedBadges(
                                  Array.isArray(me?.displayBadges) ? me.displayBadges : []
                                );
                                setBadgeEdit(false);
                              }}
                              className="px-4 py-2 bg-white border-2 border-black text-xs font-black uppercase tracking-widest hover:bg-neutral-100 transition-all"
                            >
                              Cancel
                            </button>
                          </div>
                        </div>
                      )}

                      {/* Certificates */}
                      <div className="mt-6 pt-4 border-t-2 border-black">
                        <div className="text-xs font-black uppercase tracking-widest text-black mb-3">
                          Certificates
                        </div>
                        {uniqueCerts.length === 0 ? (
                          <div className="text-xs text-slate-500 font-bold uppercase">
                            No certificates yet.
                          </div>
                        ) : (
                          <ul className="space-y-2">
                            {uniqueCerts.map((c) => (
                              <li
                                key={c.id}
                                className="flex items-center justify-between p-3 bg-white border-2 border-black"
                              >
                                <span className="text-sm font-bold text-black truncate mr-3">
                                  {c.title}
                                </span>
                                <a
                                  href={`${c.url}`}
                                  target="_blank"
                                  rel="noreferrer"
                                  className="px-3 py-1 bg-black text-white border-2 border-black text-[10px] font-black uppercase tracking-widest hover:bg-neutral-800 transition-all flex-shrink-0"
                                >
                                  Download
                                </a>
                              </li>
                            ))}
                          </ul>
                        )}
                      </div>
                    </div>
                  </>
                )}
              </div>
            )}

            {/* ── ATTENDANCE TAB ── */}
            {subTab === 'Attendance' && (
              <div>
                {attendance.length === 0 ? (
                  <div className="text-center py-12 border-2 border-dashed border-black">
                    <div className="text-xs font-black uppercase tracking-widest text-slate-500">
                      No events attended yet.
                    </div>
                  </div>
                ) : (
                  <div className="space-y-2">
                    {attendance.slice(0, 30).map((ev) => (
                      <div
                        key={ev.eventId}
                        className="flex items-center justify-between p-4 bg-white border-2 border-black hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] hover:translate-x-[-1px] hover:translate-y-[-1px] transition-all"
                      >
                        <div className="min-w-0">
                          <div className="text-sm font-black text-black uppercase tracking-tight truncate">
                            {ev.title}
                          </div>
                          <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                            {new Date(ev.date).toLocaleString()} • {ev.category || 'Event'}
                          </div>
                        </div>
                        <span
                          className={`flex-shrink-0 ml-4 px-3 py-1 border-2 border-black text-[10px] font-black uppercase tracking-wider ${ev.isCompleted ? 'bg-green-100 text-green-900' : 'bg-slate-100 text-black'}`}
                        >
                          {ev.isCompleted ? 'Completed' : 'Upcoming'}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import {
  Star,
  ArrowLeft,
  Send,
  Edit3,
  Trash2,
  User,
  Calendar,
  MapPin,
  Clock,
  CheckCircle,
  MessageSquare,
  ThumbsUp,
  ThumbsDown,
} from 'lucide-react';
import api from '../utils/api';

const bearer = () => {
  const token = localStorage.getItem('token');
  return token ? { Authorization: `Bearer ${token}` } : {};
};

export default function ReviewPage() {
  const { eventId } = useParams();
  const navigate = useNavigate();

  const [event, setEvent] = useState(null);
  const [reviewFields, setReviewFields] = useState([]);
  const [existingReview, setExistingReview] = useState(null);
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    overallRating: 0,
    reviewFields: [],
    comment: '',
    isAnonymous: false,
  });

  const canReview = Boolean(event?.isCompleted);

  useEffect(() => {
    fetchEventData();
  }, [eventId]);

  const fetchEventData = async () => {
    try {
      setLoading(true);

      // Fetch event details
      const eventRes = await api.get(`/api/host/public/events`);
      const eventData = eventRes.data.find((e) => e._id === eventId);
      setEvent(eventData);

      // Fetch review fields
      const fieldsRes = await api.get(`/api/reviews/events/${eventId}/fields`);
      setReviewFields(fieldsRes.data);

      // Initialize form data with fields
      const initialFields = fieldsRes.data.map((field) => ({
        fieldName: field.fieldName,
        fieldType: field.fieldType,
        value: '',
        rating: 0,
      }));

      setFormData((prev) => ({
        ...prev,
        reviewFields: initialFields,
      }));

      // Check if user has existing review
      try {
        const reviewRes = await api.get(`/api/reviews/events/${eventId}/reviews/my`, {
          headers: bearer(),
        });
        setExistingReview(reviewRes.data);

        // Populate form with existing review data
        if (reviewRes.data) {
          setFormData({
            overallRating: reviewRes.data.overallRating,
            reviewFields: reviewRes.data.reviewFields || initialFields,
            comment: reviewRes.data.comment || '',
            isAnonymous: reviewRes.data.isAnonymous || false,
          });
        }
      } catch (err) {
        // User hasn't reviewed yet, that's fine
        console.log('No existing review found');
      }

      // Fetch all reviews for display
      const allReviewsRes = await api.get(`/api/reviews/events/${eventId}/reviews`);
      setReviews(allReviewsRes.data.reviews || []);
    } catch (err) {
      console.error('Error fetching event data:', err);
      toast.error('Failed to load event data');
    } finally {
      setLoading(false);
    }
  };

  const handleRatingChange = (rating) => {
    setFormData((prev) => ({ ...prev, overallRating: rating }));
  };

  const handleFieldChange = (fieldName, value, rating = null) => {
    setFormData((prev) => {
      // Ensure the field exists in state; if not, add it
      const idx = prev.reviewFields.findIndex((f) => f.fieldName === fieldName);
      if (idx === -1) {
        const def = reviewFields.find((f) => f.fieldName === fieldName);
        const newEntry = {
          fieldName,
          fieldType: def?.fieldType || 'text',
          value: value ?? '',
          rating: rating ?? 0,
        };
        return { ...prev, reviewFields: [...prev.reviewFields, newEntry] };
      }
      // Update existing field; use nullish coalescing to preserve 0 ratings
      const updated = prev.reviewFields.map((f) =>
        f.fieldName === fieldName ? { ...f, value, rating: rating ?? f.rating } : f
      );
      return { ...prev, reviewFields: updated };
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!canReview) {
      toast.info('Reviews will be available once the host marks this event as completed.');
      return;
    }

    if (formData.overallRating === 0) {
      toast.error('Please provide an overall rating');
      return;
    }

    // Check required fields
    for (const field of reviewFields) {
      if (field.isRequired) {
        const formField = formData.reviewFields.find((f) => f.fieldName === field.fieldName);
        if (
          !formField ||
          (field.fieldType === 'rating' ? formField.rating === 0 : !formField.value.trim())
        ) {
          toast.error(`Please fill in the required field: ${field.fieldName}`);
          return;
        }
      }
    }

    try {
      setSubmitting(true);

      if (existingReview) {
        await api.put(`/api/reviews/events/${eventId}/reviews/my`, formData, { headers: bearer() });
        toast.success('✅ Review updated successfully!');
      } else {
        await api.post(`/api/reviews/events/${eventId}/reviews`, formData, { headers: bearer() });
        toast.success('✅ Review submitted successfully!');
      }

      // Refresh data
      await fetchEventData();
    } catch (err) {
      console.error('Error submitting review:', err);
      toast.error('❌ ' + (err?.response?.data?.error || 'Failed to submit review'));
    } finally {
      setSubmitting(false);
    }
  };

  const handleDeleteReview = async () => {
    if (!window.confirm('Are you sure you want to delete your review?')) return;

    try {
      await api.delete(`/api/reviews/events/${eventId}/reviews/my`, { headers: bearer() });
      toast.success('✅ Review deleted successfully!');
      await fetchEventData();
    } catch (err) {
      console.error('Error deleting review:', err);
      toast.error('❌ ' + (err?.response?.data?.error || 'Failed to delete review'));
    }
  };

  const renderStarRating = (rating, onRatingChange, size = 'w-6 h-6') => {
    return (
      <div className="flex items-center space-x-1">
        {[1, 2, 3, 4, 5].map((star) => (
          <button
            key={star}
            type="button"
            onClick={() => onRatingChange(star)}
            className={`${size} transition-colors duration-200 ${
              star <= rating
                ? 'text-yellow-400 fill-current'
                : 'text-gray-400 hover:text-yellow-300'
            }`}
          >
            <Star />
          </button>
        ))}
      </div>
    );
  };

  const renderField = (field) => {
    const formField = formData.reviewFields.find((f) => f.fieldName === field.fieldName);

    switch (field.fieldType) {
      case 'rating':
        return (
          <div key={field.fieldName} className="space-y-2">
            <label className="block text-sm font-medium text-gray-300">
              {field.fieldName} {field.isRequired && <span className="text-red-400">*</span>}
            </label>
            {renderStarRating(formField?.rating || 0, (rating) =>
              handleFieldChange(field.fieldName, '', rating)
            )}
          </div>
        );

      case 'text':
        return (
          <div key={field.fieldName} className="space-y-2">
            <label className="block text-sm font-medium text-gray-300">
              {field.fieldName} {field.isRequired && <span className="text-red-400">*</span>}
            </label>
            <input
              type="text"
              value={formField?.value || ''}
              onChange={(e) => handleFieldChange(field.fieldName, e.target.value)}
              placeholder={field.placeholder}
              className="w-full p-3 rounded-xl bg-gray-700/50 border border-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-300"
            />
          </div>
        );

      case 'textarea':
        return (
          <div key={field.fieldName} className="space-y-2">
            <label className="block text-sm font-medium text-gray-300">
              {field.fieldName} {field.isRequired && <span className="text-red-400">*</span>}
            </label>
            <textarea
              value={formField?.value || ''}
              onChange={(e) => handleFieldChange(field.fieldName, e.target.value)}
              placeholder={field.placeholder}
              rows="3"
              className="w-full p-3 rounded-xl bg-gray-700/50 border border-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-300"
            />
          </div>
        );

      default:
        return null;
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#f3f4f6] flex items-center justify-center font-sans tracking-tight">
        <div className="flex flex-col items-center gap-4">
          <div className="animate-spin rounded-full h-12 w-12 border-4 border-black border-t-transparent"></div>
          <p className="font-black uppercase tracking-widest text-black">Loading...</p>
        </div>
      </div>
    );
  }

  if (!event) {
    return (
      <div className="min-h-screen bg-[#f3f4f6] flex items-center justify-center font-sans tracking-tight p-4">
        <div className="text-center bg-white border-2 border-black p-8 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] max-w-md w-full">
          <h1 className="text-3xl font-black uppercase tracking-widest text-black mb-6">
            Event not found
          </h1>
          <button
            onClick={() => navigate('/dashboard')}
            className="w-full px-6 py-4 bg-yellow-400 text-black font-black uppercase tracking-widest border-2 border-black hover:bg-yellow-300 hover:-translate-y-1 hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] transition-all active:translate-y-0 active:shadow-none"
          >
            Go Back
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#f3f4f6] text-black font-sans tracking-tight">
      {/* Header */}
      <div className="bg-white border-b-2 border-black px-6 py-4 sticky top-0 z-40">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <button
              onClick={() => navigate('/dashboard')}
              className="p-3 bg-yellow-400 border-2 border-black hover:bg-yellow-300 transition-all hover:-translate-y-1 hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] active:translate-y-0 active:shadow-none"
            >
              <ArrowLeft className="w-5 h-5 text-black" />
            </button>
            <div>
              <h1 className="text-3xl font-black uppercase tracking-widest text-black">
                Review Event
              </h1>
              <p className="text-neutral-500 font-bold tracking-widest text-sm uppercase">
                Share your experience
              </p>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-4xl mx-auto p-6 space-y-8">
        {/* Event Info */}
        <div className="bg-white border-2 border-black p-6 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)]">
          <div className="flex items-start justify-between mb-4">
            <div className="flex-1">
              <h2 className="text-2xl font-black text-black mb-3">{event.title}</h2>
              <div className="flex flex-wrap items-center gap-4 text-black text-sm mb-4 font-bold uppercase tracking-widest">
                <div className="flex items-center space-x-1 bg-yellow-100 border-2 border-black px-2 py-1">
                  <Calendar className="w-4 h-4" />
                  <span>{new Date(event.date).toLocaleString()}</span>
                </div>
                <div className="flex items-center space-x-1 bg-blue-100 border-2 border-black px-2 py-1">
                  <MapPin className="w-4 h-4" />
                  <span>{event.isOnline ? 'Online' : event.location}</span>
                </div>
                {event.isCompleted && (
                  <div className="flex items-center space-x-1 bg-emerald-100 border-2 border-black px-2 py-1 text-emerald-900">
                    <CheckCircle className="w-4 h-4" />
                    <span>Completed</span>
                  </div>
                )}
              </div>
              <p className="text-neutral-700 font-medium bg-neutral-50 p-4 border-2 border-dashed border-neutral-300">
                {event.shortDescription || event.description}
              </p>
            </div>
          </div>
        </div>

        {/* Review Form */}
        <div className="bg-white border-2 border-black p-6 lg:p-8 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)]">
          <h3 className="text-2xl font-black uppercase tracking-widest text-black mb-8 flex items-center border-b-2 border-black pb-4">
            <MessageSquare className="w-8 h-8 mr-3 text-black" />
            {existingReview ? 'Update Your Review' : 'Write a Review'}
          </h3>

          {!canReview && (
            <div className="mb-6 p-4 bg-yellow-100 border-2 border-black font-bold uppercase tracking-widest text-sm text-yellow-900">
              Reviews are disabled until the host marks this event as completed.
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-8" aria-disabled={!canReview}>
            {/* Overall Rating */}
            <div className="space-y-3 bg-neutral-50 p-6 border-2 border-black">
              <label className="block text-lg font-black uppercase tracking-widest text-black">
                Overall rating <span className="text-red-600">*</span>
              </label>
              <div className={canReview ? '' : 'opacity-60 pointer-events-none'}>
                {renderStarRating(
                  formData.overallRating,
                  (r) => canReview && handleRatingChange(r),
                  'w-10 h-10'
                )}
              </div>
              {formData.overallRating > 0 && (
                <div className="text-sm font-bold uppercase tracking-widest text-neutral-600">
                  You rated this {formData.overallRating} out of 5
                </div>
              )}
            </div>
            {/* Custom Fields */}
            {reviewFields.length > 0 && (
              <div className="space-y-6">
                <h4 className="text-lg font-black uppercase tracking-widest text-black">
                  Additional Feedback
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {reviewFields.map((f) => (
                    <div
                      key={f.fieldName}
                      className={
                        canReview
                          ? 'bg-white border-2 border-black p-4'
                          : 'opacity-60 pointer-events-none bg-white border-2 border-black p-4'
                      }
                    >
                      {renderField(f)}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Comment */}
            <div className="space-y-3">
              <label className="block text-lg font-black uppercase tracking-widest text-black">
                Additional Comments
              </label>
              <textarea
                value={formData.comment}
                onChange={(e) =>
                  canReview && setFormData((prev) => ({ ...prev, comment: e.target.value }))
                }
                placeholder="Share your detailed experience..."
                rows="4"
                disabled={!canReview}
                className="w-full p-4 bg-white border-2 border-black focus:ring-4 focus:ring-blue-400 focus:outline-none transition-all block text-black font-medium resize-none placeholder:text-neutral-400"
              />
            </div>

            {/* Anonymous Option */}
            <div className="flex items-center space-x-3 bg-neutral-50 p-4 border-2 border-black w-max cursor-pointer hover:bg-neutral-100 transition-colors">
              <input
                type="checkbox"
                id="isAnonymous"
                checked={formData.isAnonymous}
                onChange={(e) =>
                  canReview && setFormData((prev) => ({ ...prev, isAnonymous: e.target.checked }))
                }
                className="w-5 h-5 text-black bg-white border-2 border-black rounded-none focus:ring-2 focus:ring-black focus:ring-offset-2 appearance-none checked:bg-black relative
                  after:content-[''] after:absolute after:hidden checked:after:block after:left-[6px] after:top-[2px] after:w-[5px] after:h-[10px] after:border-white after:border-b-2 after:border-r-2 after:rotate-45"
              />
              <label
                htmlFor="isAnonymous"
                className="font-bold uppercase tracking-widest text-sm text-black cursor-pointer"
              >
                Submit anonymously
              </label>
            </div>

            {/* Submit Buttons */}
            <div className="flex flex-wrap items-center gap-4 pt-6 mt-6 border-t-2 border-black">
              <button
                type="submit"
                disabled={submitting || !canReview}
                className="flex items-center space-x-2 px-8 py-4 bg-black text-white font-black uppercase tracking-widest border-2 border-transparent hover:bg-neutral-800 transition-colors hover:-translate-y-1 hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] active:translate-y-0 active:shadow-none disabled:opacity-50 disabled:pointer-events-none"
              >
                <Send className="w-5 h-5" />
                <span>
                  {submitting
                    ? 'Submitting...'
                    : existingReview
                      ? 'Update Review'
                      : 'Submit Review'}
                </span>
              </button>

              {existingReview && (
                <button
                  type="button"
                  onClick={handleDeleteReview}
                  className="flex items-center space-x-2 px-8 py-4 bg-red-100 text-red-700 font-black uppercase tracking-widest border-2 border-red-700 hover:bg-red-200 transition-colors hover:-translate-y-1 hover:shadow-[4px_4px_0px_0px_rgba(185,28,28,1)] active:translate-y-0 active:shadow-none"
                >
                  <Trash2 className="w-5 h-5" />
                  <span>Delete Review</span>
                </button>
              )}
            </div>
          </form>
        </div>

        {/* Reviews Display */}
        {reviews.length > 0 && (
          <div className="bg-white border-2 border-black p-6 lg:p-8 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] mt-8">
            <h3 className="text-2xl font-black uppercase tracking-widest text-black mb-8 flex items-center border-b-2 border-black pb-4">
              <Star className="w-8 h-8 mr-3 text-black" />
              Reviews ({reviews.length})
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {reviews.map((review, idx) => (
                <div
                  key={idx}
                  className="bg-neutral-50 border-2 border-black p-6 hover:-translate-y-1 hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] transition-all flex flex-col group"
                >
                  <div className="flex items-start justify-between mb-4 border-b-2 border-black pb-4">
                    <div className="flex items-center space-x-3">
                      <div className="w-12 h-12 bg-white border-2 border-black rounded-full flex items-center justify-center overflow-hidden">
                        <User className="w-6 h-6 text-black" />
                      </div>
                      <div>
                        <p className="font-black uppercase tracking-widest text-black text-sm">
                          {review.isAnonymous
                            ? 'Anonymous'
                            : review.reviewerId?.fullname || 'Unknown'}
                        </p>
                        <p className="text-neutral-500 font-bold tracking-widest text-xs uppercase">
                          {new Date(review.createdAt).toLocaleDateString()}
                        </p>
                      </div>
                    </div>
                  </div>

                  {/* Rating */}
                  <div className="flex items-center space-x-1 mb-4">
                    {renderStarRating(review.overallRating, () => {}, 'w-5 h-5')}
                  </div>

                  {/* Custom Fields */}
                  {review.reviewFields && review.reviewFields.length > 0 && (
                    <div className="mb-4 bg-white border-2 border-black p-4 space-y-2">
                      {review.reviewFields.map((field, fieldIdx) => (
                        <div key={fieldIdx} className="flex items-center justify-between">
                          <span className="text-xs font-black text-black uppercase tracking-widest">
                            {field.fieldName}
                          </span>
                          {field.fieldType === 'rating' ? (
                            <div className="inline-flex items-center">
                              {renderStarRating(field.rating, () => {}, 'w-3 h-3')}
                            </div>
                          ) : (
                            <span className="text-sm text-neutral-600 font-bold uppercase tracking-widest">
                              {field.value}
                            </span>
                          )}
                        </div>
                      ))}
                    </div>
                  )}

                  {review.comment && (
                    <div className="mt-auto pt-4 relative">
                      <div className="absolute left-0 top-4 bottom-0 w-1 bg-black"></div>
                      <p className="text-black text-sm font-medium leading-relaxed italic pl-4">
                        "{review.comment}"
                      </p>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// src/pages/Settings.jsx
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../utils/api';
import {
  Bell,
  Lock,
  Sliders,
  Zap,
  ShieldCheck,
  Link2,
  User,
  ChevronRight,
  ArrowLeft,
  CheckCircle,
  XCircle,
  Eye,
  Activity,
  History,
  Download,
  Trash2,
} from 'lucide-react';

// ── Brutalist Toggle ──────────────────────────────────────────────
function Toggle({ checked, onChange, disabled }) {
  return (
    <button
      type="button"
      role="switch"
      aria-checked={checked}
      onClick={() => !disabled && onChange(!checked)}
      disabled={disabled}
      className={`relative w-14 h-7 border-2 border-black transition-all duration-150 shadow-[3px_3px_0px_0px_rgba(0,0,0,1)] focus:outline-none ${disabled ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer hover:shadow-[5px_5px_0px_0px_rgba(0,0,0,1)] hover:translate-x-[-1px] hover:translate-y-[-1px]'} ${checked ? 'bg-black' : 'bg-white'}`}
    >
      <span
        className={`absolute top-0.5 w-5 h-5 border-2 border-black transition-all duration-150 ${checked ? 'left-[calc(100%_-_22px)] bg-white' : 'left-0.5 bg-black'}`}
      />
    </button>
  );
}

// ── Brutalist Setting Row ─────────────────────────────────────────
function SettingRow({ label, desc, checked, onChange, disabled }) {
  return (
    <div className="flex items-center justify-between p-4 bg-white border-2 border-black hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] hover:translate-x-[-1px] hover:translate-y-[-1px] transition-all">
      <div className="flex-1 pr-6">
        <div className="text-sm font-black text-black uppercase tracking-tight">{label}</div>
        {desc && <div className="text-xs text-slate-500 font-medium mt-0.5">{desc}</div>}
      </div>
      <Toggle checked={checked} onChange={onChange} disabled={disabled} />
    </div>
  );
}

// ── Tab definition ────────────────────────────────────────────────
const TABS = [
  { id: 'Profile', icon: User, color: 'bg-blue-50' },
  { id: 'Notifications', icon: Bell, color: 'bg-amber-50' },
  { id: 'Privacy', icon: Lock, color: 'bg-pink-50' },
  { id: 'Accessibility', icon: Eye, color: 'bg-cyan-50' },
  { id: 'Activity', icon: Activity, color: 'bg-indigo-50' },
  { id: 'Preferences', icon: Sliders, color: 'bg-violet-50' },
  { id: 'Recommendations', icon: Zap, color: 'bg-green-50' },
  { id: 'Security', icon: ShieldCheck, color: 'bg-teal-50' },
  { id: 'Connected Apps', icon: Link2, color: 'bg-orange-50' },
];

export default function Settings() {
  const [activeTab, setActiveTab] = useState('Profile');
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [userEmail, setUserEmail] = useState('');
  const [settings, setSettings] = useState({
    notifications: {
      email: true,
      eventReminders: true,
      newFromFollowedHosts: true,
      friendRequests: true,
    },
    privacy: {
      onlyFriendsCanViewProfile: false,
      allowFriendRequests: true,
      searchableByEmail: true,
      showBadgesPublic: true,
      incognitoMode: false,
    },
    ui: { density: 'comfortable', sidebarCollapsedDefault: false },
    accessibility: { reduceMotion: false, highContrast: false },
    recommendations: { personalizeUsingOnboarding: true, showTrendingFirst: true },
    connectedApps: { googleLinked: false },
  });
  const [verify, setVerify] = useState({ emailVerified: false, phoneVerified: false });
  const navigate = useNavigate();

  useEffect(() => {
    const load = async () => {
      try {
        const { data } = await api.get('/api/auth/settings');
        const s = data?.settings || {};
        setSettings({
          notifications: {
            email: s?.notifications?.email !== false,
            eventReminders: s?.notifications?.eventReminders !== false,
            newFromFollowedHosts: s?.notifications?.newFromFollowedHosts !== false,
            friendRequests: s?.notifications?.friendRequests !== false,
          },
          privacy: {
            onlyFriendsCanViewProfile: !!s?.privacy?.onlyFriendsCanViewProfile,
            allowFriendRequests: s?.privacy?.allowFriendRequests !== false,
            searchableByEmail: s?.privacy?.searchableByEmail !== false,
            showBadgesPublic: s?.privacy?.showBadgesPublic !== false,
            incognitoMode: !!s?.privacy?.incognitoMode,
          },
          ui: {
            density: s?.ui?.density || 'comfortable',
            sidebarCollapsedDefault: !!s?.ui?.sidebarCollapsedDefault,
          },
          accessibility: {
            reduceMotion: !!s?.accessibility?.reduceMotion,
            highContrast: !!s?.accessibility?.highContrast,
          },
          recommendations: {
            personalizeUsingOnboarding: s?.recommendations?.personalizeUsingOnboarding !== false,
            showTrendingFirst: s?.recommendations?.showTrendingFirst !== false,
          },
          connectedApps: { googleLinked: !!s?.connectedApps?.googleLinked },
        });
        const density = s?.ui?.density || 'comfortable';
        document.documentElement.setAttribute('data-density', density);
        try {
          localStorage.setItem('ui_density', density);
        } catch {}
        try {
          localStorage.setItem(
            'ui_sidebar_collapsed_default',
            String(!!s?.ui?.sidebarCollapsedDefault)
          );
        } catch {}
        setVerify({ emailVerified: !!data?.emailVerified, phoneVerified: !!data?.phoneVerified });
        setUserEmail(data?.email || '');
      } catch (e) {
        toast.error(e?.response?.data?.error || 'Failed to load settings');
      } finally {
        setLoading(false);
      }
    };
    load();
  }, []);

  const saveSettings = async (partial) => {
    try {
      setSaving(true);
      await api.put('/api/auth/settings', partial);
      setSettings((prev) => {
        const merged = JSON.parse(JSON.stringify(prev));
        if (partial.notifications) Object.assign(merged.notifications, partial.notifications);
        if (partial.privacy) Object.assign(merged.privacy, partial.privacy);
        if (partial.ui) Object.assign(merged.ui, partial.ui);
        if (partial.accessibility) Object.assign(merged.accessibility, partial.accessibility);
        if (partial.recommendations) Object.assign(merged.recommendations, partial.recommendations);
        return merged;
      });
      if (partial.ui?.density) {
        document.documentElement.setAttribute('data-density', partial.ui.density);
        try {
          localStorage.setItem('ui_density', partial.ui.density);
        } catch {}
      }
      if (typeof partial.ui?.sidebarCollapsedDefault === 'boolean') {
        try {
          localStorage.setItem(
            'ui_sidebar_collapsed_default',
            String(!!partial.ui.sidebarCollapsedDefault)
          );
        } catch {}
      }
      toast.success('Settings saved');
    } catch (e) {
      toast.error(e?.response?.data?.error || 'Failed to save settings');
    } finally {
      setSaving(false);
    }
  };

  const clearSearchHistory = () => {
    toast.info('Clearing search history...', { icon: <History className="w-4 h-4" /> });
    const key = userEmail ? `student.recentSearches:${userEmail}` : 'student.recentSearches';
    try {
      localStorage.removeItem(key);
      setTimeout(() => toast.success('Search history cleared'), 1000);
    } catch (e) {
      toast.error('Failed to clear history');
    }
  };

  const downloadData = () => {
    toast.info('Preparing your data for download...', { icon: <Download className="w-4 h-4" /> });
    setTimeout(() => toast.success('Your data package is ready! Check your email.'), 2000);
  };

  const activeTabDef = TABS.find((t) => t.id === activeTab) || TABS[0];
  const ActiveIcon = activeTabDef.icon;

  return (
    <div className="min-h-screen bg-neutral-50 selection:bg-black selection:text-white">
      {/* ── Sticky header ── */}
      <header className="sticky top-0 z-30 bg-white border-b-2 border-black shadow-[0_4px_0px_0px_rgba(0,0,0,1)]">
        <div className="max-w-5xl mx-auto px-4 md:px-6 py-4 flex items-center gap-4">
          <button
            onClick={() => navigate('/dashboard')}
            className="p-2 border-2 border-black bg-white shadow-[3px_3px_0px_0px_rgba(0,0,0,1)] hover:shadow-[5px_5px_0px_0px_rgba(0,0,0,1)] hover:translate-x-[-1px] hover:translate-y-[-1px] transition-all"
          >
            <ArrowLeft className="w-5 h-5 text-black" />
          </button>
          <div className="p-2.5 bg-black border-2 border-black">
            <Sliders className="w-5 h-5 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black text-black uppercase tracking-tighter">Settings</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
              Manage your account preferences
            </p>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto p-4 md:p-6">
        <div className="grid grid-cols-1 md:grid-cols-5 gap-6 items-start">
          {/* ── Sidebar nav ── */}
          <aside className="md:col-span-2 lg:col-span-1 border-2 border-black bg-white shadow-[6px_6px_0px_0px_rgba(0,0,0,1)]">
            {TABS.map((tab, idx) => {
              const Icon = tab.icon;
              const isActive = activeTab === tab.id;
              return (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`w-full flex items-center gap-3 px-4 py-3.5 text-left transition-all border-b-2 border-black last:border-b-0 ${isActive ? 'bg-black text-white' : 'bg-white text-black hover:bg-neutral-100'}`}
                >
                  <Icon className="w-4 h-4 flex-shrink-0" />
                  <span className="text-xs font-black uppercase tracking-widest">{tab.id}</span>
                  {isActive && <ChevronRight className="w-3.5 h-3.5 ml-auto" />}
                </button>
              );
            })}
          </aside>

          {/* ── Content panel ── */}
          <section className="md:col-span-3 lg:col-span-4">
            <div
              className={`border-2 border-black shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] min-h-[300px] ${activeTabDef.color}`}
            >
              {/* Panel header */}
              <div className="flex items-center gap-3 px-6 py-4 border-b-2 border-black bg-white">
                <div className="p-2 border-2 border-black bg-black">
                  <ActiveIcon className="w-4 h-4 text-white" />
                </div>
                <h2 className="text-sm font-black text-black uppercase tracking-widest">
                  {activeTab}
                </h2>
                {saving && (
                  <span className="ml-auto text-[10px] font-black uppercase tracking-widest text-slate-500 flex items-center gap-1.5">
                    <div className="w-3 h-3 border-2 border-black border-t-transparent animate-spin" />{' '}
                    Saving...
                  </span>
                )}
              </div>

              {/* Panel body */}
              <div className="p-6">
                {loading ? (
                  <div className="flex items-center gap-3 py-8 text-black font-black uppercase tracking-widest text-xs">
                    <div className="w-4 h-4 border-2 border-black border-t-transparent animate-spin" />{' '}
                    Loading settings...
                  </div>
                ) : (
                  <>
                    {/* ── PROFILE ── */}
                    {activeTab === 'Profile' && (
                      <div className="space-y-4">
                        <p className="text-xs text-slate-600 font-bold uppercase tracking-widest">
                          Manage your public profile information on the Profile page.
                        </p>
                        <button
                          onClick={() => navigate('/profile')}
                          className="flex items-center gap-2 px-5 py-3 bg-black text-white border-2 border-black font-black uppercase tracking-widest text-xs shadow-[4px_4px_0px_0px_rgba(0,0,0,0.3)] hover:bg-neutral-800 hover:shadow-[6px_6px_0px_0px_rgba(0,0,0,0.3)] transition-all"
                        >
                          <User className="w-4 h-4" /> Go to Profile
                        </button>
                      </div>
                    )}

                    {/* ── NOTIFICATIONS ── */}
                    {activeTab === 'Notifications' && (
                      <div className="space-y-2">
                        {[
                          {
                            key: 'email',
                            label: 'General emails',
                            desc: 'Product updates and important notices',
                          },
                          {
                            key: 'eventReminders',
                            label: 'Event reminders',
                            desc: 'Reminders for registered events',
                          },
                          {
                            key: 'newFromFollowedHosts',
                            label: 'Followed hosts',
                            desc: 'New events from hosts you follow',
                          },
                          {
                            key: 'friendRequests',
                            label: 'Friend requests',
                            desc: 'Requests and activity from friends',
                          },
                        ].map((opt) => (
                          <SettingRow
                            key={opt.key}
                            label={opt.label}
                            desc={opt.desc}
                            checked={!!settings.notifications[opt.key]}
                            onChange={(val) => saveSettings({ notifications: { [opt.key]: val } })}
                            disabled={saving}
                          />
                        ))}
                      </div>
                    )}

                    {/* ── PRIVACY ── */}
                    {activeTab === 'Privacy' && (
                      <div className="space-y-2">
                        {[
                          {
                            key: 'incognitoMode',
                            label: 'Incognito Mode',
                            desc: 'Hide your presence from others while browsing',
                          },
                          {
                            key: 'onlyFriendsCanViewProfile',
                            label: 'Friends-only profile',
                            desc: 'Restrict profile visibility to friends',
                          },
                          {
                            key: 'allowFriendRequests',
                            label: 'Allow friend requests',
                            desc: 'Receive requests from other users',
                          },
                          {
                            key: 'searchableByEmail',
                            label: 'Searchable by email',
                            desc: 'Allow others to find you by email',
                          },
                          {
                            key: 'showBadgesPublic',
                            label: 'Show badges publicly',
                            desc: 'Display your badges on profile',
                          },
                        ].map((opt) => (
                          <SettingRow
                            key={opt.key}
                            label={opt.label}
                            desc={opt.desc}
                            checked={!!settings.privacy[opt.key]}
                            onChange={(val) => saveSettings({ privacy: { [opt.key]: val } })}
                            disabled={saving}
                          />
                        ))}
                      </div>
                    )}

                    {/* ── ACCESSIBILITY ── */}
                    {activeTab === 'Accessibility' && (
                      <div className="space-y-2">
                        {[
                          {
                            key: 'reduceMotion',
                            label: 'Reduce Motion',
                            desc: 'Minimize animations and transitions',
                          },
                          {
                            key: 'highContrast',
                            label: 'High Contrast',
                            desc: 'Increase color contrast for better readability',
                          },
                        ].map((opt) => (
                          <SettingRow
                            key={opt.key}
                            label={opt.label}
                            desc={opt.desc}
                            checked={!!settings.accessibility[opt.key]}
                            onChange={(val) => saveSettings({ accessibility: { [opt.key]: val } })}
                            disabled={saving}
                          />
                        ))}
                      </div>
                    )}

                    {/* ── ACTIVITY ── */}
                    {activeTab === 'Activity' && (
                      <div className="space-y-4">
                        <div className="p-4 bg-white border-2 border-black hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] transition-all flex items-center justify-between">
                          <div>
                            <div className="text-sm font-black text-black uppercase tracking-tight">
                              Search History
                            </div>
                            <div className="text-xs text-slate-500 font-medium mt-0.5">
                              Clear your recent search queries
                            </div>
                          </div>
                          <button
                            onClick={clearSearchHistory}
                            className="px-4 py-2 border-2 border-black bg-white text-xs font-black uppercase tracking-widest hover:bg-red-50 transition-all flex items-center gap-2"
                          >
                            <Trash2 className="w-3.5 h-3.5" /> Clear
                          </button>
                        </div>
                        <div className="p-4 bg-white border-2 border-black hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] transition-all flex items-center justify-between">
                          <div>
                            <div className="text-sm font-black text-black uppercase tracking-tight">
                              Personal Data
                            </div>
                            <div className="text-xs text-slate-500 font-medium mt-0.5">
                              Download a copy of your account data
                            </div>
                          </div>
                          <button
                            onClick={downloadData}
                            className="px-4 py-2 border-2 border-black bg-black text-white text-xs font-black uppercase tracking-widest hover:bg-neutral-800 transition-all flex items-center gap-2"
                          >
                            <Download className="w-3.5 h-3.5" /> Download
                          </button>
                        </div>
                      </div>
                    )}

                    {/* ── PREFERENCES ── */}
                    {activeTab === 'Preferences' && (
                      <div className="space-y-4">
                        <SettingRow
                          label="Show Email in Public Profile"
                          desc="Let others see your email address on your profile"
                          checked={!!settings.privacy?.showEmail}
                          onChange={(val) => saveSettings({ privacy: { showEmail: val } })}
                          disabled={saving}
                        />
                        <SettingRow
                          label="Collapsed Sidebar by Default"
                          desc="Start with the navigation sidebar minimized"
                          checked={!!settings.ui?.sidebarCollapsedDefault}
                          onChange={(val) => saveSettings({ ui: { sidebarCollapsedDefault: val } })}
                          disabled={saving}
                        />

                        {/* Density selector */}
                        <div className="p-4 bg-white border-2 border-black">
                          <div className="text-sm font-black text-black uppercase tracking-tight mb-3">
                            UI Density
                          </div>
                          <div className="flex gap-2">
                            {['compact', 'comfortable', 'spacious'].map((d) => (
                              <button
                                key={d}
                                onClick={() => saveSettings({ ui: { density: d } })}
                                disabled={saving}
                                className={`flex-1 px-3 py-2.5 border-2 border-black text-[10px] font-black uppercase tracking-widest transition-all shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] hover:translate-x-[-1px] hover:translate-y-[-1px] ${settings.ui.density === d ? 'bg-black text-white' : 'bg-white text-black'}`}
                              >
                                {d}
                              </button>
                            ))}
                          </div>
                        </div>
                      </div>
                    )}

                    {/* ── RECOMMENDATIONS ── */}
                    {activeTab === 'Recommendations' && (
                      <div className="space-y-2">
                        {[
                          {
                            key: 'personalizeUsingOnboarding',
                            label: 'Personalize from onboarding',
                            desc: 'Use your onboarding preferences for recommendations',
                          },
                          {
                            key: 'showTrendingFirst',
                            label: 'Trending first',
                            desc: 'Prioritize trending events in Explore',
                          },
                        ].map((opt) => (
                          <SettingRow
                            key={opt.key}
                            label={opt.label}
                            desc={opt.desc}
                            checked={!!settings.recommendations[opt.key]}
                            onChange={(val) =>
                              saveSettings({ recommendations: { [opt.key]: val } })
                            }
                            disabled={saving}
                          />
                        ))}
                      </div>
                    )}

                    {/* ── SECURITY ── */}
                    {activeTab === 'Security' && (
                      <div className="space-y-4">
                        {/* Verification status cards */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                          <div
                            className={`p-4 border-2 border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] flex items-center gap-3 ${verify.emailVerified ? 'bg-green-50' : 'bg-red-50'}`}
                          >
                            {verify.emailVerified ? (
                              <CheckCircle className="w-5 h-5 text-green-700 flex-shrink-0" />
                            ) : (
                              <XCircle className="w-5 h-5 text-red-700 flex-shrink-0" />
                            )}
                            <div>
                              <div className="text-xs font-black uppercase tracking-widest text-black">
                                Email
                              </div>
                              <div
                                className={`text-[10px] font-black uppercase tracking-widest ${verify.emailVerified ? 'text-green-700' : 'text-red-700'}`}
                              >
                                {verify.emailVerified ? 'Verified ✓' : 'Not Verified'}
                              </div>
                            </div>
                          </div>
                          <div
                            className={`p-4 border-2 border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] flex items-center gap-3 ${verify.phoneVerified ? 'bg-green-50' : 'bg-red-50'}`}
                          >
                            {verify.phoneVerified ? (
                              <CheckCircle className="w-5 h-5 text-green-700 flex-shrink-0" />
                            ) : (
                              <XCircle className="w-5 h-5 text-red-700 flex-shrink-0" />
                            )}
                            <div>
                              <div className="text-xs font-black uppercase tracking-widest text-black">
                                Phone
                              </div>
                              <div
                                className={`text-[10px] font-black uppercase tracking-widest ${verify.phoneVerified ? 'text-green-700' : 'text-red-700'}`}
                              >
                                {verify.phoneVerified ? 'Verified ✓' : 'Not Verified'}
                              </div>
                            </div>
                          </div>
                        </div>

                        {/* Action buttons */}
                        <div className="flex gap-3 flex-wrap">
                          <button
                            onClick={() => navigate('/profile?tab=otp')}
                            className="flex items-center gap-2 px-5 py-3 bg-black text-white border-2 border-black font-black uppercase tracking-widest text-xs shadow-[4px_4px_0px_0px_rgba(0,0,0,0.3)] hover:bg-neutral-800 transition-all"
                          >
                            <ShieldCheck className="w-4 h-4" /> Verify Credentials
                          </button>
                          <button
                            onClick={() => navigate('/reset-password')}
                            className="flex items-center gap-2 px-5 py-3 bg-white text-black border-2 border-black font-black uppercase tracking-widest text-xs shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] hover:shadow-[6px_6px_0px_0px_rgba(0,0,0,1)] hover:translate-x-[-1px] hover:translate-y-[-1px] active:shadow-none active:translate-x-[2px] active:translate-y-[2px] transition-all"
                          >
                            Change Password
                          </button>
                        </div>
                      </div>
                    )}

                    {/* ── CONNECTED APPS ── */}
                    {activeTab === 'Connected Apps' && (
                      <div className="space-y-2">
                        <div className="flex items-center justify-between p-4 bg-white border-2 border-black hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] hover:translate-x-[-1px] hover:translate-y-[-1px] transition-all">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 border-2 border-black bg-white flex items-center justify-center shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] text-xl font-black">
                              G
                            </div>
                            <div>
                              <div className="text-sm font-black text-black uppercase tracking-tight">
                                Google
                              </div>
                              <div className="text-xs text-slate-500 font-medium">
                                Linked for OAuth login
                              </div>
                            </div>
                          </div>
                          <span
                            className={`px-3 py-1.5 border-2 border-black text-[10px] font-black uppercase tracking-widest ${settings.connectedApps.googleLinked ? 'bg-green-100 text-green-900' : 'bg-neutral-100 text-black'}`}
                          >
                            {settings.connectedApps.googleLinked ? 'Linked ✓' : 'Not Linked'}
                          </span>
                        </div>
                      </div>
                    )}
                  </>
                )}
              </div>
            </div>
          </section>
        </div>
      </main>
    </div>
  );
}
